## Implementation (from §9.4 of spec)

```tsx
import { useState, useEffect, useRef } from 'react';
import { BookOpen, Sparkles, User, Users } from 'lucide-react';
import { cn, truncateMiddle } from '@/layers/shared/lib';
import { CollapsibleCard } from '../primitives';

interface MemoryRecallBlockProps {
  mode: 'select' | 'synthesize';
  memories: Array<{ path: string; scope: 'personal' | 'team'; content?: string }>;
  isStreaming: boolean;
}

/**
 * Top-of-bubble lifecycle indicator for SDK memory_recall events.
 *
 * Four visual states mirroring ThinkingBlock: streaming (breathing label),
 * collapsing (auto on stream end), collapsed chip ("Recalled N memories"),
 * expanded (vertical list of recalled paths or synthesis paragraph).
 */
export function MemoryRecallBlock({ mode, memories, isStreaming }: MemoryRecallBlockProps) {
  const [expanded, setExpanded] = useState(isStreaming);
  const wasStreamingRef = useRef(isStreaming);

  // Auto-collapse when streaming completes — mirrors ThinkingBlock exactly
  useEffect(() => {
    if (wasStreamingRef.current && !isStreaming) {
      setExpanded(false); // eslint-disable-line react-hooks/set-state-in-effect -- Intentional: collapse once on streaming→done transition
    }
    wasStreamingRef.current = isStreaming;
  }, [isStreaming]);

  if (memories.length === 0) {
    // Defense in depth: a memory_recall part with zero memories is a bug upstream.
    // Render nothing rather than an empty chip.
    return null;
  }

  const count = memories.length;
  const headerLabel = isStreaming
    ? count <= 1
      ? 'Consulting memory…'
      : `Consulting ${count} memories…`
    : count === 1
      ? 'Recalled 1 memory'
      : `Recalled ${count} memories`;

  const HeaderIcon = mode === 'synthesize' ? Sparkles : BookOpen;

  return (
    <CollapsibleCard
      expanded={expanded}
      onToggle={() => setExpanded(!expanded)}
      variant="memory"
      dimmed={!isStreaming}
      disabled={isStreaming}
      ariaLabel={headerLabel}
      data-testid="memory-recall-block"
      data-streaming={isStreaming ? 'true' : undefined}
      header={
        <>
          <HeaderIcon
            className={cn(
              'text-muted-foreground size-(--size-icon-xs)',
              isStreaming && 'animate-tasks'
            )}
          />
          <span
            className={cn(
              'text-3xs text-muted-foreground font-mono',
              isStreaming && 'animate-tasks'
            )}
          >
            {headerLabel}
          </span>
        </>
      }
    >
      <MemoryRecallList memories={memories} mode={mode} />
    </CollapsibleCard>
  );
}

function MemoryRecallList({
  memories,
  mode: _topLevelMode,
}: {
  memories: MemoryRecallBlockProps['memories'];
  mode: MemoryRecallBlockProps['mode'];
}) {
  return (
    <ul className="flex flex-col gap-1 px-3 py-2">
      {memories.map((m) => (
        <MemoryRecallRow key={m.path} memory={m} />
      ))}
    </ul>
  );
}

function MemoryRecallRow({
  memory,
}: {
  memory: MemoryRecallBlockProps['memories'][number];
}) {
  const isSynthesis = memory.path.startsWith('<synthesis:');
  const ScopeIcon = memory.scope === 'team' ? Users : User;
  const scopeLabel = memory.scope === 'team' ? 'Team memory' : 'Personal memory';

  const handleCopy = async () => {
    const payload = isSynthesis && memory.content ? memory.content : memory.path;
    try {
      await navigator.clipboard.writeText(payload);
      // Toast via existing DorkOS toast system — adapt to repo pattern
      // (likely imported from '@/layers/shared/ui' or a toast hook).
    } catch {
      // Show error toast
    }
  };

  if (isSynthesis && memory.content) {
    const displayDir = memory.path.replace(/^<synthesis:/, 'synthesis:').replace(/>$/, '');
    return (
      <li>
        <button
          type="button"
          onClick={handleCopy}
          aria-label="Copy synthesized memory content"
          className="focus-ring flex min-h-[44px] w-full flex-col items-start gap-1 rounded-md px-2 py-1 text-left hover:bg-muted/50"
        >
          <span className="text-sm">{memory.content}</span>
          <span className="flex items-center gap-1 text-3xs text-muted-foreground font-mono">
            <ScopeIcon aria-label={scopeLabel} className="size-(--size-icon-xs)" />
            {displayDir}
          </span>
        </button>
      </li>
    );
  }

  return (
    <li>
      <button
        type="button"
        onClick={handleCopy}
        aria-label={`Copy path ${memory.path}`}
        className="focus-ring flex min-h-[44px] w-full items-center gap-2 rounded-md px-2 py-1 text-left hover:bg-muted/50"
      >
        <span className="text-sm font-mono flex-1 truncate">
          {truncateMiddle(memory.path, 40)}
        </span>
        <ScopeIcon
          aria-label={scopeLabel}
          className="text-muted-foreground size-(--size-icon-xs)"
        />
      </button>
    </li>
  );
}
```

